  // Source: JPL Horizons / Astronomical Almanac
  eccentricityJ2000: 0.01671022,                     // Earth eccentricity at J2000.0
  perihelionLongitudeJ2000_deg: 102.947,             // Longitude of perihelion at J2000.0
