// Mercury: No moons, mass determined from Mariner 10 and MESSENGER spacecraft
const MASS_RATIO_SUN_MERCURY = 6023625.5;            // DE440
const GM_MERCURY = GM_SUN / MASS_RATIO_SUN_MERCURY;  // ~22,032 km³/s²
