/** Interpolate La2010 data. col: 1=ecc, 2=inclination, 3=periLong, 4=ascNode */
function _la2010Interp(yearFromJ2000, col) {
  if (yearFromJ2000 < _LA2010[0][0] || yearFromJ2000 > _LA2010[_LA2010.length - 1][0]) return NaN;
  const idx = (yearFromJ2000 - _LA2010[0][0]) / 2000; // 2 kyr steps
  const i = Math.floor(idx);
  if (i >= _LA2010.length - 1) return _LA2010[_LA2010.length - 1][col];
  const frac = idx - i;
  let a = _LA2010[i][col], b = _LA2010[i + 1][col];
  // Handle 360° wrapping for angular columns (ascending node, perihelion longitude)
  if (col >= 3 && Math.abs(b - a) > 180) {
    if (b > a) a += 360; else b += 360;
    return ((a * (1 - frac) + b * frac) % 360 + 360) % 360;
  }
  return a * (1 - frac) + b * frac;
}

function inclinationLa2010(year) { return _la2010Interp(year - 2000, 2); }
function ascNodeLa2010(year) { return _la2010Interp(year - 2000, 4); }

/** Model ascending node on invariable plane — retrograde at -H/5 (confirmed by La2010 N-body solution) */
function ascNodeModel(year) {
  return ((earthAscendingNodeInvPlaneVerified + (360 / (-holisticyearLength / 5)) * (year - 2000)) % 360 + 360) % 360;
}

