       value : [ { v: () => OrbitalFormulas.perihelionVelocity(marsOrbitDistance * o.lengthofAU, planets.mars.orbitalEccentricityBase) * 3600, dec:2, sep:',' },{ small: 'km/h' }],
       hover : [`Maximum orbital velocity at perihelion: vₚ = √(GM/a) × √((1+e)/(1-e))`],
